import { MongoClient, ServerApiVersion } from 'mongodb';

import { envKeys } from '@config/env.config';

import { FolderModel } from '@models/folder.model';
import { NoteModel } from '@models/note.model';

import { getEnv } from '@utils/get-env.util';

import type { Db } from 'mongodb';

const dbUser = getEnv<string>({ key: envKeys.DB_USER, converter: String });
const dbPassword = getEnv<string>({ key: envKeys.DB_PASSWORD, converter: String });
const dbName = getEnv<string>({ key: envKeys.DB_NAME, converter: String });
const dbDomain = getEnv<string>({ key: envKeys.DB_DOMAIN, converter: String });

const uri = `mongodb+srv://${dbUser}:${dbPassword}@${dbDomain}/?appName=${dbName}`;

const client = new MongoClient(uri, {
	serverApi: {
		version: ServerApiVersion.v1,
		strict: true,
		deprecationErrors: true,
	},
});

let db: Db;
let folderModel: FolderModel;
let noteModel: NoteModel;

export const MDB = async (): Promise<MongoClient> => {
	try {
		await client.connect();
		db = client.db(dbName);
		await db.command({ ping: 1 });

		// Initialize models
		folderModel = new FolderModel(db);
		noteModel = new NoteModel(db);

		// eslint-disable-next-line no-console
		console.log('Connected successfully to MongoDB server');
		return client;
	} catch (error) {
		// eslint-disable-next-line no-console
		console.error('Failed to connect to MongoDB server:', error);
		throw error;
	}
};

export const getDb = (): Db => {
	if (!db) {
		throw new Error('Database not initialized. Call MDB() first.');
	}
	return db;
};

export const getFolderModel = (): FolderModel => {
	if (!folderModel) {
		throw new Error('FolderModel not initialized. Call MDB() first.');
	}
	return folderModel;
};

export const getNoteModel = (): NoteModel => {
	if (!noteModel) {
		throw new Error('NoteModel not initialized. Call MDB() first.');
	}
	return noteModel;
};

