import { envConfig } from '@config/env.config';

export const getEnv = <T>({
	key,
	converter,
}: {
	key: string;
	converter?: (param: unknown) => T;
}): T => {
	// eslint-disable-next-line
	console.log(
		`Fetching environment variable: ${key}, converter: ${converter ? converter.name : 'none'}`,
	);

	const envVariable = envConfig[key as keyof typeof envConfig];

	if (envVariable === undefined) {
		throw new Error(`Environment variable ${key} is not defined`);
	}

	return converter ? converter(envVariable) : (envVariable as T);
};

