import { randomUUID } from 'node:crypto';

import type { IFolder } from '@interfaces/folder.interface';

import type { Collection, Db } from 'mongodb';

export class FolderModel {
	private collection: Collection<IFolder>;

	constructor(db: Db) {
		this.collection = db.collection<IFolder>('folders');
		this.initializeCollection().catch((error: unknown) => {
			/* eslint-disable-next-line no-console */
			console.error('Failed to initialize folders collection:', error);
		});
	}

	private async initializeCollection(): Promise<void> {
		await this.collection.createIndex({ id: 1 }, { unique: true });
		await this.collection.createIndex({ parentId: 1 });
		await this.collection.createIndex({ name: 1 });

		await this.collection.db.command({
			collMod: 'folders',
			validator: {
				$jsonSchema: {
					bsonType: 'object',
					required: ['id', 'name', 'createdAt', 'updatedAt'],
					properties: {
						id: {
							bsonType: 'string',
							description: 'Unique identifier for the folder',
						},
						name: {
							bsonType: 'string',
							minLength: 1,
							maxLength: 255,
							description: 'Folder name',
						},
						parentId: {
							bsonType: ['string', 'null'],
							description: 'Parent folder ID or null for root folders',
						},
						createdAt: {
							bsonType: 'date',
							description: 'Creation timestamp',
						},
						updatedAt: {
							bsonType: 'date',
							description: 'Last update timestamp',
						},
					},
				},
			},
			validationLevel: 'strict',
			validationAction: 'error',
		});
	}

	public async create(name: string, parentId: string | null): Promise<IFolder> {
		const folder: IFolder = {
			id: randomUUID(),
			name,
			parentId,
			createdAt: new Date(),
			updatedAt: new Date(),
		};

		await this.collection.insertOne(folder);
		return folder;
	}

	public async findById(id: string): Promise<IFolder | null> {
		return this.collection.findOne({ id });
	}

	public async findAll(): Promise<IFolder[]> {
		return this.collection.find({}).toArray();
	}

	public async findByParentId(parentId: string | null): Promise<IFolder[]> {
		return this.collection.find({ parentId }).toArray();
	}

	public async update(id: string, updates: Partial<IFolder>): Promise<IFolder | null> {
		const result = await this.collection.findOneAndUpdate(
			{ id },
			{ $set: { ...updates, updatedAt: new Date() } },
			{ returnDocument: 'after' },
		);

		return result ?? null;
	}

	public async delete(id: string): Promise<boolean> {
		const result = await this.collection.deleteOne({ id });
		return result.deletedCount === 1;
	}

	public async countChildren(parentId: string): Promise<number> {
		return this.collection.countDocuments({ parentId });
	}

	public async hasChildren(parentId: string): Promise<boolean> {
		const count = await this.countChildren(parentId);
		return count > 0;
	}
}

