import * as http from 'node:http';

import { MDB } from '@config/db-connection.config';
import { envKeys } from '@config/env.config';

import { createWebSocketServer } from '@modules/websocket/websocket.server';

import { getEnv } from '@utils/get-env.util';

const port = getEnv<number>({ key: envKeys.PORT, converter: Number });
const host = getEnv<string>({ key: envKeys.HOST, converter: String });

const requestListener: http.RequestListener = (_, res) => {
	res.writeHead(200, { 'Content-Type': 'text/plain' });
	res.end('WebSocket server is running\n');
};

const server = http.createServer(requestListener);

const startServer = async (): Promise<void> => {
	try {
		await MDB();
		server.listen(port, host, () => {
			// eslint-disable-next-line no-console
			console.log(`Server is running on http://${host}:${port}`);
			// eslint-disable-next-line no-console
			console.log(`WebSocket server is ready`);

			// Initialize WebSocket server
			createWebSocketServer(server);
		});
	} catch (error) {
		// eslint-disable-next-line no-console
		console.error('Failed to start server:', error);
		process.exit(1);
	}
};

startServer().catch((error: unknown) => {
	// eslint-disable-next-line no-console
	console.error('Unexpected error during server startup:', error);
	process.exit(1);
});

